import{_ as e,c as d,o as a,a4 as o}from"./chunks/framework.DQgBWl2g.js";const u=JSON.parse('{"title":"日语基础语法","description":"","frontmatter":{"title":"日语基础语法"},"headers":[],"relativePath":"language/Japanese/index.md","filePath":"language/Japanese/index.md"}'),r={name:"language/Japanese/index.md"};function l(c,t,i,h,n,s){return a(),d("div",null,[...t[0]||(t[0]=[o('<h2 id="文字系统" tabindex="-1">文字系统 <a class="header-anchor" href="#文字系统" aria-label="Permalink to &quot;文字系统&quot;">​</a></h2><p>日语使用三种文字：汉字、平假名、片假名。</p><h3 id="汉字-kanji" tabindex="-1">汉字（Kanji） <a class="header-anchor" href="#汉字-kanji" aria-label="Permalink to &quot;汉字（Kanji）&quot;">​</a></h3><ul><li>约 2000 个汉字就占了实际书写中使用的 95% 以上。</li><li>汉字对于区分句子中的不同单词至关重要。</li><li>名词以及形容词和动词的词干几乎都用汉字来书写，副词也常常用汉字表示。</li></ul><h3 id="平假名-hiragana" tabindex="-1">平假名（Hiragana） <a class="header-anchor" href="#平假名-hiragana" aria-label="Permalink to &quot;平假名（Hiragana）&quot;">​</a></h3><p>平假名主要用于表达语法意义。</p><h3 id="片假名-katakana" tabindex="-1">片假名（Katakana） <a class="header-anchor" href="#片假名-katakana" aria-label="Permalink to &quot;片假名（Katakana）&quot;">​</a></h3><ul><li>片假名所代表的发音与平假名相同，但主要用于表示从西方国家引进的新词。</li><li>也可像斜体字一样，用来突出某些词语。</li><li>由于日语中没有空格，有时会使用 <code>・</code> 来表示空格。</li></ul><blockquote><p>ロック・アンド・ロール</p></blockquote><hr><h2 id="发音-intonation" tabindex="-1">发音（Intonation） <a class="header-anchor" href="#发音-intonation" aria-label="Permalink to &quot;发音（Intonation）&quot;">​</a></h2><h3 id="长元音" tabindex="-1">长元音 <a class="header-anchor" href="#长元音" aria-label="Permalink to &quot;长元音&quot;">​</a></h3><p>可根据不同元音的特点，分别加上 <code>あ</code>、<code>い</code> 或 <code>う</code> 来延长相应元音的发音时间。发出长元音时，这两个音是合二为一的。</p><p><strong>平假名</strong>：少数情况下，/e/ 元音音节通过添加 <code>え</code> 来延长，/o/ 元音音节通过添加 <code>お</code> 来延长。</p><p><strong>片假名</strong>：所有长元音统一用一个短横 <code>ー</code> 来表示。</p><h3 id="小写元音「ァ、ィ、ゥ、ェ、ォ」" tabindex="-1">小写元音「ァ、ィ、ゥ、ェ、ォ」 <a class="header-anchor" href="#小写元音「ァ、ィ、ゥ、ェ、ォ」" aria-label="Permalink to &quot;小写元音「ァ、ィ、ゥ、ェ、ォ」&quot;">​</a></h3><p>由于平假名音素的局限性，人们创造了这五个元音的小写形式来表示原本不存在于日语中的音素。</p><table tabindex="0"><thead><tr><th style="text-align:center;">v</th><th style="text-align:center;">w</th><th style="text-align:center;">f</th><th style="text-align:center;">ch</th><th style="text-align:center;">d</th><th style="text-align:center;">t</th><th style="text-align:center;">j</th><th style="text-align:center;">sh</th><th style="text-align:center;"></th></tr></thead><tbody><tr><td style="text-align:center;"><strong>ヴァ</strong></td><td style="text-align:center;">ワ</td><td style="text-align:center;"><strong>ファ</strong></td><td style="text-align:center;">チャ</td><td style="text-align:center;">ダ</td><td style="text-align:center;">タ</td><td style="text-align:center;">ジャ</td><td style="text-align:center;">シャ</td><td style="text-align:center;"><strong>a</strong></td></tr><tr><td style="text-align:center;"><strong>ヴィ</strong></td><td style="text-align:center;"><strong>ウィ</strong></td><td style="text-align:center;"><strong>フィ</strong></td><td style="text-align:center;">チ</td><td style="text-align:center;"><strong>ディ</strong></td><td style="text-align:center;"><strong>ティ</strong></td><td style="text-align:center;">ジ</td><td style="text-align:center;">シ</td><td style="text-align:center;"><strong>i</strong></td></tr><tr><td style="text-align:center;"><strong>ヴ</strong></td><td style="text-align:center;">ウ</td><td style="text-align:center;">フ</td><td style="text-align:center;">チュ</td><td style="text-align:center;"><strong>ドゥ</strong></td><td style="text-align:center;"><strong>トゥ</strong></td><td style="text-align:center;">ジュ</td><td style="text-align:center;">シュ</td><td style="text-align:center;"><strong>u</strong></td></tr><tr><td style="text-align:center;"><strong>ヴェ</strong></td><td style="text-align:center;"><strong>ウェ</strong></td><td style="text-align:center;"><strong>フェ</strong></td><td style="text-align:center;"><strong>チェ</strong></td><td style="text-align:center;">デ</td><td style="text-align:center;">テ</td><td style="text-align:center;"><strong>ジェ</strong></td><td style="text-align:center;"><strong>シェ</strong></td><td style="text-align:center;"><strong>e</strong></td></tr><tr><td style="text-align:center;"><strong>ヴォ</strong></td><td style="text-align:center;"><strong>ウォ</strong></td><td style="text-align:center;"><strong>フォ</strong></td><td style="text-align:center;">チョ</td><td style="text-align:center;">ド</td><td style="text-align:center;">ト</td><td style="text-align:center;">ジョ</td><td style="text-align:center;">ショ</td><td style="text-align:center;"><strong>o</strong></td></tr></tbody></table><hr><h2 id="汉字的读法" tabindex="-1">汉字的读法 <a class="header-anchor" href="#汉字的读法" aria-label="Permalink to &quot;汉字的读法&quot;">​</a></h2><p>几乎每个汉字都有两种不同的读法：</p><table tabindex="0"><thead><tr><th>读法</th><th>说明</th></tr></thead><tbody><tr><td><strong>音読</strong>（音读み）</td><td>汉字原本的汉语读音，多用于复合词或固定搭配中</td></tr><tr><td><strong>訓読</strong>（訓读み）</td><td>日语中的读音，多用于单独使用的汉字</td></tr></tbody></table><ul><li>某些汉字（尤其是最常见的那些）可能有多种不同的音读或训读方式。</li><li>还有一些复合词的读音与各个组成汉字的读音无关，需要单独记忆。</li><li>实际上，大多数单词通常只用一个汉字来表示，而且大多数汉字的读音也都不超过两种。</li></ul><h3 id="送假名-送り仮名" tabindex="-1">送假名（送り仮名） <a class="header-anchor" href="#送假名-送り仮名" aria-label="Permalink to &quot;送假名（送り仮名）&quot;">​</a></h3><p>訓读也用于形容词和动词中。这类词通常会附带一串假名，称为送假名。这样即使单词变成不同形态时，汉字的读音也能保持不变。</p><h3 id="音变" tabindex="-1">音变 <a class="header-anchor" href="#音变" aria-label="Permalink to &quot;音变&quot;">​</a></h3><p>在复合词中，汉字的读音会稍作变化，以便于发音。常见的变化包括：</p><ul><li><code>h</code> 音变成 <code>b</code> 或 <code>p</code> 音</li><li><code>つ</code> 变成 <code>っ</code></li></ul><h3 id="重复符号「々」" tabindex="-1">重复符号「々」 <a class="header-anchor" href="#重复符号「々」" aria-label="Permalink to &quot;重复符号「々」&quot;">​</a></h3><p><code>々</code> 并不是真正的汉字，它只表示前面的字符需要重复书写。例如，「时时」、「様様」都可以写作「时々」、「様々」。</p><hr><h2 id="基础语法" tabindex="-1">基础语法 <a class="header-anchor" href="#基础语法" aria-label="Permalink to &quot;基础语法&quot;">​</a></h2><h3 id="状态表达-だ" tabindex="-1">状态表达：<code>だ</code> <a class="header-anchor" href="#状态表达-だ" aria-label="Permalink to &quot;状态表达：`だ`&quot;">​</a></h3><p>日语中没有像英语中 <code>be</code> 这样的表示状态的动词。在<strong>名词</strong>或<strong>な形容词</strong>后加上 <code>だ</code> 来表示某物的状态。</p><table tabindex="0"><thead><tr><th>形式</th><th>结构</th><th>例句</th></tr></thead><tbody><tr><td>肯定</td><td>名词/ナ形 + だ</td><td>学生だ。（是学生。）</td></tr><tr><td>否定</td><td>名词/ナ形 + じゃない</td><td>学生じゃない。（不是学生。）</td></tr><tr><td>过去</td><td>名词/ナ形 + だった</td><td>学生だった。（曾是学生。）</td></tr><tr><td>过去否定</td><td>名词/ナ形 + じゃなかった</td><td>学生じゃなかった。（曾不是学生。）</td></tr></tbody></table><p><strong>注意：</strong></p><ul><li><code>だ</code> 能让句子听起来更加强调和有力，更符合陈述句的特点。</li><li>男性经常在句子末尾使用 <code>だ</code>。</li><li>完全可以不用 <code>だ</code> 来表达「某人是学生」这样的意思。</li><li>如果从上下文就能明白主语是谁，可以不必明确指出主语。</li></ul><p><strong>否定形式的变形逻辑：</strong></p><p>否定：<code>名词/ナ形 + じゃない</code></p><p>过去否定：将 <code>じゃない</code> 的 <code>い</code> 去掉，加上 <code>かった</code>，得到 <code>じゃなかった</code>。</p><hr><h3 id="助词-particles" tabindex="-1">助词（Particles） <a class="header-anchor" href="#助词-particles" aria-label="Permalink to &quot;助词（Particles）&quot;">​</a></h3><p>助词是由一个或多个平假名组成的字符，加在单词的末尾，用来确定该单词在句子中的语法功能。</p><h4 id="主题助词「は」" tabindex="-1">主题助词「は」 <a class="header-anchor" href="#主题助词「は」" aria-label="Permalink to &quot;主题助词「は」&quot;">​</a></h4><ul><li><code>は</code> 读作 /ha/，但作为主题助词使用时，读作 /wa/。</li><li>主题助词用于表明句子所谈论的内容，即句子的 <mark>主题</mark>。</li></ul><blockquote><p>ジョンは明日。 // 至于约翰，是明天。</p></blockquote><h4 id="包含性主题助词「も」" tabindex="-1">包含性主题助词「も」 <a class="header-anchor" href="#包含性主题助词「も」" aria-label="Permalink to &quot;包含性主题助词「も」&quot;">​</a></h4><p><code>も</code> 在话题标记的基础上增加了「也」的含义，用于引入与当前话题相关的另一个话题。</p><blockquote><p>アリス：トムは学生？ ボブ：うん、トムも学生。 // 是的，汤姆也是学生。</p></blockquote><blockquote><p>アリス：でもトムは学生じゃない。 // 但是汤姆不是学生。 ボブ：ううん、トムも学生じゃない。 // 不，汤姆也不是学生。</p></blockquote><h4 id="指代助词「が」" tabindex="-1">指代助词「が」 <a class="header-anchor" href="#指代助词「が」" aria-label="Permalink to &quot;指代助词「が」&quot;">​</a></h4><p>当我们不知道话题到底是什么时，<code>が</code> 就派上用场了。它可以看作在回答一个隐含的问题。</p><table tabindex="0"><thead><tr><th>句子</th><th>含义</th></tr></thead><tbody><tr><td>誰が学生？</td><td>谁是那个学生？（谁 = 未知信息）</td></tr><tr><td>学生は誰？</td><td>那个学生是谁？（学生 = 已知话题）</td></tr></tbody></table><blockquote><p>私は学生。 // 至于我，我是学生。 私が学生。 // 我（就是）那个学生。→ 回答「谁是学生？」这个问题</p></blockquote><p><strong>「は」与「が」的区分：</strong></p><table tabindex="0"><thead><tr><th>助词</th><th>作用</th><th>语言思维</th></tr></thead><tbody><tr><td>は</td><td>标记主题</td><td>「至于……；关于……」</td></tr><tr><td>が</td><td>标记指代</td><td>「那个……；这件事……」</td></tr></tbody></table><hr><h3 id="形容词-adjectives" tabindex="-1">形容词（Adjectives） <a class="header-anchor" href="#形容词-adjectives" aria-label="Permalink to &quot;形容词（Adjectives）&quot;">​</a></h3><p>形容词可以直接修饰其后面的名词。所有形容词分为两类：<mark>ナ形容詞</mark> 和 <mark>イ形容詞</mark>。</p><h4 id="ナ形容詞-na-adjective" tabindex="-1">ナ形容詞（na-adjective） <a class="header-anchor" href="#ナ形容詞-na-adjective" aria-label="Permalink to &quot;ナ形容詞（na-adjective）&quot;">​</a></h4><ul><li>ナ形容詞本质上相当于名词。</li><li>直接修饰名词时，在形容词与名词之间加 <code>な</code>。</li><li>变形规则与名词相同。</li></ul><table tabindex="0"><thead><tr><th>用法</th><th>例句</th></tr></thead><tbody><tr><td>谓语</td><td>友達は親切。 // 朋友很亲切。</td></tr><tr><td>修饰</td><td>友達は親切な人だ。 // 朋友是个亲切的人。</td></tr><tr><td>否定</td><td>友達は親切じゃない。 // 朋友不亲切。</td></tr></tbody></table><p><strong>「好き」的特殊用法：</strong></p><blockquote><p>ボブは魚が好きだ。 // 鲍勃喜欢鱼。</p></blockquote><p>可以将 <code>好き</code> 理解为「令人向往的 / 想要的」。这句话的主题是「鲍勃」，而「鱼」则具体指明了鲍勃所喜欢的东西——这是主题词与指示词协同使用的典型例子。</p><p><strong>从句修饰：</strong></p><blockquote><p>魚が好きな人。 // 喜欢鱼的人。</p></blockquote><p><code>魚が好き</code>、<code>魚が好きじゃない</code> 等整个短语都是用来修饰 <code>人</code> 的。</p><h4 id="イ形容詞-i-adjective" tabindex="-1">イ形容詞（i-adjective） <a class="header-anchor" href="#イ形容詞-i-adjective" aria-label="Permalink to &quot;イ形容詞（i-adjective）&quot;">​</a></h4><ul><li>所有的イ形容词都以平假名 <code>い</code> 结尾。</li><li>直接修饰名词时<strong>无需</strong>加上 <code>な</code>。</li><li>不能像名词否定形式那样加上陈述用的 <code>だ</code>。</li></ul><table tabindex="0"><thead><tr><th>用法</th><th>例句</th></tr></thead><tbody><tr><td>修饰</td><td>高いレストラン // 贵的餐厅</td></tr><tr><td>从句修饰</td><td>値段が高いレストラン // 价格贵的餐厅</td></tr></tbody></table><p><strong>例外：「いい」</strong></p><p>所有变形都要以 <code>よい</code> 为基础，而不是 <code>いい</code>。</p><blockquote><p>いい → よくない（否定） いい → よかった（过去）</p></blockquote><blockquote><p>以 <code>い</code> 结尾的ナ形容词很少，而且通常不使用汉字书写。几乎所有其他以 <code>い</code> 结尾的ナ形容词都用汉字书写。</p></blockquote><hr><h3 id="动词基础-verb-basics" tabindex="-1">动词基础（Verb Basics） <a class="header-anchor" href="#动词基础-verb-basics" aria-label="Permalink to &quot;动词基础（Verb Basics）&quot;">​</a></h3><p>在日语中，动词总是位于句子的末尾。一个语法完整的句子只需要一个动词即可。</p><h4 id="常见动词" tabindex="-1">常见动词 <a class="header-anchor" href="#常见动词" aria-label="Permalink to &quot;常见动词&quot;">​</a></h4><table tabindex="0"><thead><tr><th>动词</th><th>类型</th><th>含义</th></tr></thead><tbody><tr><td>いる</td><td>ru-动词</td><td>存在（有生命物体）</td></tr><tr><td>ある</td><td>u-动词</td><td>存在（无生命物体）</td></tr><tr><td>着る（きる）</td><td>ru-动词</td><td>穿</td></tr><tr><td>する</td><td>例外</td><td>做 / 进行</td></tr><tr><td>くる</td><td>例外</td><td>来</td></tr></tbody></table><h4 id="动词分类" tabindex="-1">动词分类 <a class="header-anchor" href="#动词分类" aria-label="Permalink to &quot;动词分类&quot;">​</a></h4><p>除了两个例外动词外，所有动词都属于 <mark>ru-动词</mark> 或 <mark>u-动词</mark> 两类：</p><table tabindex="0"><thead><tr><th>类型</th><th>特征</th></tr></thead><tbody><tr><td><strong>ru-动词</strong></td><td>以 <code>る</code> 结尾</td></tr><tr><td><strong>u-动词</strong></td><td>可以以包括 <code>る</code> 在内的多种 u-元音发音结尾</td></tr></tbody></table><p><strong>判断规则：</strong></p><ul><li>不以 <code>る</code> 结尾 → 一定是 u-动词</li><li>以 <code>る</code> 结尾，且 <code>る</code> 前面的元音是 /a/、/u/ 或 /o/ → u-动词</li><li>以 <code>る</code> 结尾，且前面的元音是 /i/ 或 /e/ → 大多数情况下是 ru-动词</li></ul><blockquote><p>以「い」段假名结尾的 ru-动词 又称之为 <strong>上一段动词</strong>。 以「え」段假名结尾的 ru-动词 又称之为 <strong>下一段动词</strong>。</p></blockquote><h4 id="否定形" tabindex="-1">否定形 <a class="header-anchor" href="#否定形" aria-label="Permalink to &quot;否定形&quot;">​</a></h4><p>将动词变为否定形式，表示「某项动作并没有发生」。</p><ul><li><p>对于 ru-动词：去掉「る」，加上「ない」</p><blockquote><p>食べる + ない = 食べない</p></blockquote></li><li><p>对于以「う」结尾的 u-动词：把「う」变成「わ」，再加上「ない」</p><blockquote><p>買う + わ + ない = 買わない</p></blockquote></li><li><p>对于其他所有 u-动词：把う段假名改为对应的あ段假名，再加上「ない」</p><blockquote><p>待つ → 待た + ない = 待たない</p></blockquote></li><li><p>特殊动词：</p><ol><li>する → しない</li><li>くる → こない</li><li>ある → ない</li></ol></li></ul><h4 id="过去式" tabindex="-1">过去式 <a class="header-anchor" href="#过去式" aria-label="Permalink to &quot;过去式&quot;">​</a></h4><h5 id="ru-动词" tabindex="-1">ru-动词 <a class="header-anchor" href="#ru-动词" aria-label="Permalink to &quot;ru-动词&quot;">​</a></h5><p>去 <code>る</code> + <code>た</code>。</p><h5 id="u-动词" tabindex="-1">u-动词 <a class="header-anchor" href="#u-动词" aria-label="Permalink to &quot;u-动词&quot;">​</a></h5><p>按照词尾分为四类：</p><table tabindex="0"><thead><tr><th>词尾</th><th>变化</th><th>例句</th></tr></thead><tbody><tr><td>す</td><td>す → した</td><td>話す → 話した</td></tr><tr><td>く</td><td>く → いた</td><td>書く → 書いた</td></tr><tr><td>ぐ</td><td>ぐ → いだ</td><td>泳ぐ → 泳いだ</td></tr><tr><td>む/ぶ/ぬ</td><td>→ んだ</td><td>読む → 読んだ、遊ぶ → 遊んだ、死ぬ → 死んだ</td></tr><tr><td>る/う/つ</td><td>→ った</td><td>作る → 作った、買う → 買った、待つ → 待った</td></tr></tbody></table><blockquote><p><strong>⚠ 例外：</strong> 行く → 行った（不是 <code>行いた</code>）</p></blockquote><h4 id="过去否定式" tabindex="-1">过去否定式 <a class="header-anchor" href="#过去否定式" aria-label="Permalink to &quot;过去否定式&quot;">​</a></h4><p>规则对所有动词统一：取动词的否定形式 → 去掉 <code>ない</code> 结尾中的 <code>い</code> → 用 <code>かった</code> 替换。</p><blockquote><p>行く → 行かない → 行かなかった 食べる → 食べない → 食べなかった する → しない → しなかった</p></blockquote><hr><h3 id="与动词搭配的助词" tabindex="-1">与动词搭配的助词 <a class="header-anchor" href="#与动词搭配的助词" aria-label="Permalink to &quot;与动词搭配的助词&quot;">​</a></h3><h4 id="宾语助词「を」" tabindex="-1">宾语助词「を」 <a class="header-anchor" href="#宾语助词「を」" aria-label="Permalink to &quot;宾语助词「を」&quot;">​</a></h4><ul><li>在单词末尾加上 <code>を</code>，表示该词是动词的 <mark>直接宾语</mark>。</li><li><code>を</code> 的发音是 /wo/，但在实际说话中听起来更接近 /o/。</li><li><code>を</code> 这个字符从来不会用在其他地方（其片假名形式 <code>ヲ</code> 也几乎从不使用）。</li></ul><blockquote><p>⾼速道路を⾛る。// Run through expressway.</p></blockquote><p>当名词与 <code>する</code> 连用时，<code>を</code> 可以省略，<code>[noun + する]</code> 结构可视为一个动词。</p><blockquote><p>毎⽇、⽇本语を勉强する。// Study Japanese everyday.</p></blockquote><h4 id="目标助词「に」" tabindex="-1">目标助词「に」 <a class="header-anchor" href="#目标助词「に」" aria-label="Permalink to &quot;目标助词「に」&quot;">​</a></h4><p><code>に</code> 表示动词的 <mark>作用对象</mark>——动词是朝向与 <code>に</code> 相连的词语来发挥作用的。</p><table tabindex="0"><thead><tr><th>对比</th><th>を</th><th>に</th></tr></thead><tbody><tr><td>作用</td><td>动词对直接宾语施加动作</td><td>动词朝向目标发挥作用</td></tr><tr><td>搭配</td><td>及物动词</td><td>所有表示移动的动词</td></tr></tbody></table><ul><li>所有表示移动的动词，其作用对象都由 <code>に</code> 来指定。</li><li>目标助词始终表示「向……去」。</li></ul><blockquote><p>家に帰らない。// Not go back home. ボブは⽇本に⾏った。 // Bob went to Japan.</p></blockquote><p>如果想表达「从……来」，必须使用 <code>から</code>。<code>から</code> 还经常与 <code>まで</code> 连用，表示「直到……为止」：</p><blockquote><p>宿題を今日から明日までする。 // 作业从今天做到明天。</p></blockquote><p>在日语中，「​目标」 这一概念非常通用，并不限于表示运动的动词。例如，对于表示「存在」的动词（ある和いる）​，物体的位置可以被视为其目标。时间也是一种常见的「​目标」。</p><p><strong>「に」与存在动词：</strong></p><blockquote><p>いい友达に会った。 // Met good friend. 无生命用 <code>ある</code> 猫は部屋にいる。 // Cat is in room. 有生命用 <code>いる</code></p></blockquote><p><strong>「に」与时间：</strong></p><p>使用 <code>に</code> 后，日期变成具体的目标时间点，强调动作在那个时间发生；不使用则没有特别强调意味。</p><blockquote><p>来年、日本に行く。 // 明年去日本。——一般陈述 来年に日本に行く。 // 在明年去日本。——强调时间点</p></blockquote><h4 id="方向助词「へ」" tabindex="-1">方向助词「へ」 <a class="header-anchor" href="#方向助词「へ」" aria-label="Permalink to &quot;方向助词「へ」&quot;">​</a></h4><ul><li>虽然 <code>へ</code> 的通常发音是 /he/，但作为助词使用时，发音始终为 /e/（え）。</li></ul><table tabindex="0"><thead><tr><th>助词</th><th>含义</th></tr></thead><tbody><tr><td>に</td><td>以某个目标为最终目的地（明确）</td></tr><tr><td>へ</td><td>正朝着该目标的方向前进（模糊）</td></tr></tbody></table><ul><li><code>へ</code> 只能与表示方向性的动词搭配使用。</li><li><code>へ</code> 并不能确保该目标就是最终的终点。</li><li>对于没有物理移动方向的动词，不能使用 <code>へ</code>。</li><li><code>へ</code> 也可以表示朝着抽象概念的方向：</li></ul><blockquote><p>勝ちへ向かう。 // 朝着胜利前进。</p></blockquote><h4 id="场景助词「で」" tabindex="-1">场景助词「で」 <a class="header-anchor" href="#场景助词「で」" aria-label="Permalink to &quot;场景助词「で」&quot;">​</a></h4><p><code>で</code> 帮助明确动作发生的 <mark>背景或环境</mark>。可以理解为「通过……的方式」。</p><blockquote><p>映画馆で⾒た。// Saw at movie theater. レストランで昼ご饭を⾷べた。// Ate lunch at restaurant.</p></blockquote><p><strong>「何で」的读法：</strong></p><p><code>何</code> 通常读作 <code>なに</code>，但有时读作 <code>なん</code>。建议先一直使用 <code>なに</code> 直到有人指出何时应读 <code>なん</code>。</p><blockquote><p>何できた？ // 怎么来的？——<code>で</code> 在此表示方式</p></blockquote><p><code>なんで</code> 是独立的词，意为「为什么」，与助词 <code>で</code> 无直接关系。</p><hr><h3 id="主题化-当地点-宾语成为主题时" tabindex="-1">主题化：当地点 / 宾语成为主题时 <a class="header-anchor" href="#主题化-当地点-宾语成为主题时" aria-label="Permalink to &quot;主题化：当地点 / 宾语成为主题时&quot;">​</a></h3><h4 id="地点是主题" tabindex="-1">地点是主题 <a class="header-anchor" href="#地点是主题" aria-label="Permalink to &quot;地点是主题&quot;">​</a></h4><p>将主题助词 <code>は</code> 和 <code>も</code> 加在表示地点的三个助词 <code>に</code>、<code>へ</code>、<code>で</code> 之后。</p><blockquote><p>ボブ：どこで食べる？ アリス：イタリアレストランではどう？ // Bob: Where should we eat? Alice: How about Italian restaurant?</p></blockquote><h4 id="宾语是主题" tabindex="-1">宾语是主题 <a class="header-anchor" href="#宾语是主题" aria-label="Permalink to &quot;宾语是主题&quot;">​</a></h4><p>话题可以不用 <code>を</code> 标记就作为直接宾语。如果加上了 <code>を</code> 标记反而会变成错误表达。</p><blockquote><p>❌ 日本語をは、習う。 // 错误！</p></blockquote><hr><h3 id="及物动词与不及物动词" tabindex="-1">及物动词与不及物动词 <a class="header-anchor" href="#及物动词与不及物动词" aria-label="Permalink to &quot;及物动词与不及物动词&quot;">​</a></h3><p>也称为 <strong>他动词</strong> ，<strong>自动词</strong>。</p><table tabindex="0"><thead><tr><th>类型</th><th>特征</th></tr></thead><tbody><tr><td><strong>及物动词</strong></td><td>有施事者实施的动作</td></tr><tr><td><strong>不及物动词</strong></td><td>无需施事者就能发生的动作</td></tr></tbody></table><p>一般而言，有：</p><ul><li><p>「す」结尾的动词，几乎都是他动词，其自动词往往变成「れる／える」段。</p></li><li><p>「ある」结尾的动词，几乎都是自动词，其他动词往往是「える」段。</p></li><li><p>「おす」 结尾的他动词，自动词多是「いる」段。</p></li></ul><p>如果动词以 「える」 结尾，有时是他动词（閉める），有时是自动词（消える），需要结合对应词来判断。</p><table tabindex="0"><thead><tr><th>及物</th><th>不及物</th></tr></thead><tbody><tr><td>電気を消す。 // 关灯。</td><td>電気が消える。 // 灯灭了。</td></tr><tr><td>ボールを落とした。 // 球被弄掉了。</td><td>ボールが落ちた。 // 球掉了。</td></tr></tbody></table><p><strong>关键点：</strong></p><ul><li>不及物动词不能有直接宾语。</li><li>只有表示运动的动词的地点才可以用 <code>を</code> 搭配不及物动词。</li></ul><hr><h3 id="定语从句与语序" tabindex="-1">定语从句与语序 <a class="header-anchor" href="#定语从句与语序" aria-label="Permalink to &quot;定语从句与语序&quot;">​</a></h3><h4 id="将动词和状态词视为形容词来处理" tabindex="-1">将动词和状态词视为形容词来处理 <a class="header-anchor" href="#将动词和状态词视为形容词来处理" aria-label="Permalink to &quot;将动词和状态词视为形容词来处理&quot;">​</a></h4><p>动词的否定形、过去式及过去否定式可以像形容词一样<mark>直接</mark>用来修饰名词：</p><table tabindex="0"><thead><tr><th>形式</th><th>修饰名词</th></tr></thead><tbody><tr><td>动词否定</td><td>食べない人 // 不吃的人</td></tr><tr><td>动词过去</td><td>食べた人 // 吃了的人</td></tr><tr><td>动词过去否定</td><td>食べなかった人 // 没吃的人</td></tr></tbody></table><p><strong>例外：</strong> 对于用 <code>だ</code> 表示的单纯非过去时态，无法如此使用（需要用 <code>の</code> 或 <code>な</code>）。</p><h4 id="状态从句用作形容词" tabindex="-1">状态从句用作形容词 <a class="header-anchor" href="#状态从句用作形容词" aria-label="Permalink to &quot;状态从句用作形容词&quot;">​</a></h4><blockquote><p>友達じゃなかったアリスは、いい友達になった。 // 曾经不是朋友的 Alice，变成了好朋友。</p></blockquote><h4 id="动词从句修饰名词" tabindex="-1">动词从句修饰名词 <a class="header-anchor" href="#动词从句修饰名词" aria-label="Permalink to &quot;动词从句修饰名词&quot;">​</a></h4><p>动词从句也可以像形容词一样用来修饰名词：</p><blockquote><p>晩ご飯を食べなかった人は、映画で見た銀行に行った。 // 没吃晚饭的人去了在电影里看到的银行。</p></blockquote><h4 id="名词修饰名词" tabindex="-1">名词修饰名词 <a class="header-anchor" href="#名词修饰名词" aria-label="Permalink to &quot;名词修饰名词&quot;">​</a></h4><p>当多个名词并非相互修饰的关系时，可以将它们直接连在一起：</p><blockquote><p>国際教育センター // 国际教育中心</p></blockquote><p>这些名词之间没有任何语法上的连接关系。有时候某些组合使用得如此频繁，以至于它们几乎变成了独立的单词。</p><hr><h3 id="日语句子语序" tabindex="-1">日语句子语序 <a class="header-anchor" href="#日语句子语序" aria-label="Permalink to &quot;日语句子语序&quot;">​</a></h3><p>日语句子结构的核心规则：</p><ul><li><strong>一个完整的句子必须有谓语动词，且该动词必须放在句尾。</strong></li><li>在动词之前出现的成分可以没有固定的顺序，只要有了动词，句子就成立了。</li><li>这就是使用助词的意义所在——无论单词在句子中的位置如何，助词都能明确其语法功能。</li><li>除了 <code>だ</code> 之外，可以用定语从句来修饰名词，从而构成复合句。</li></ul><blockquote><p>私は公园でお弁当を⾷べた。// 我在公园里吃了便当。 公园で私はお弁当を⾷べた。 お弁当を私は公园で⾷べた。</p></blockquote><hr><h2 id="名词相关助词" tabindex="-1">名词相关助词 <a class="header-anchor" href="#名词相关助词" aria-label="Permalink to &quot;名词相关助词&quot;">​</a></h2><h3 id="并列助词「と」" tabindex="-1">并列助词「と」 <a class="header-anchor" href="#并列助词「と」" aria-label="Permalink to &quot;并列助词「と」&quot;">​</a></h3><p>把两个或多个名词组合起来，表示「和」的意思。</p><blockquote><p>本と雑志と叶书を买った。// Bought book, magazine, and post card.</p></blockquote><p><code>と</code> 的另一个类似用法是表示与某人或某物一起完成的动作。</p><blockquote><p>友达と话した。Talked with friend.</p></blockquote><h3 id="模糊列举「や」和「とか」" tabindex="-1">模糊列举「や」和「とか」 <a class="header-anchor" href="#模糊列举「や」和「とか」" aria-label="Permalink to &quot;模糊列举「や」和「とか」&quot;">​</a></h3><table tabindex="0"><thead><tr><th>助词</th><th>特点</th></tr></thead><tbody><tr><td>や</td><td>模糊列举，暗示可能还有其他未列出的事物；理解为「和/或等等」</td></tr><tr><td>とか</td><td>与 <code>や</code> 意思相同，但用法更口语化</td></tr></tbody></table><blockquote><p>饮み物やカップやナプキンは、いらない？// You don&#39;t need (things like) drink,cup, or napkin, etc.?</p></blockquote><blockquote><p>靴とかシャツを买う。// Buy (things like) shoes and shirt, etc...</p></blockquote><h3 id="「の」助词" tabindex="-1">「の」助词 <a class="header-anchor" href="#「の」助词" aria-label="Permalink to &quot;「の」助词&quot;">​</a></h3><p><code>の</code> 用途繁多，是非常重要的助词。</p><h4 id="所有格-名词化" tabindex="-1">所有格 / 名词化 <a class="header-anchor" href="#所有格-名词化" aria-label="Permalink to &quot;所有格 / 名词化&quot;">​</a></h4><blockquote><p>ボブの本。// Book of Bob.</p></blockquote><p>如果上下文能够明确表明省略了什么内容，被修饰的名词就可以省略。</p><blockquote><p>そのシャツは誰のシャツ？ → そのシャツは誰の？ // 那件衬衫是谁的？</p></blockquote><p><code>の</code> 可以直接当做名词，表示<strong>一般类事物</strong>，此时该名词并非句子重点。</p><blockquote><p>⽩いのは、かわいい。// Thing that is white is cute.</p></blockquote><blockquote><p>⽩い物は、かわいい。Thing that is white is cute.</p></blockquote><p>使用ナ形容词来修饰 <code>の</code> 时，仍然需要加上“な”。</p><blockquote><p>静かなのが、アリスの部屋だ。// Quiet one is room of Alice.</p></blockquote><table tabindex="0"><thead><tr><th>词汇</th><th>来源</th><th>意思</th></tr></thead><tbody><tr><td>この</td><td>これの 演变</td><td>这个（近称）</td></tr><tr><td>その</td><td>それ + の 缩写形式</td><td>那个（中称）</td></tr><tr><td>あの</td><td>あれの 演变</td><td>那个（远称）</td></tr></tbody></table><h4 id="「の」的解释性用法" tabindex="-1">「の」的解释性用法 <a class="header-anchor" href="#「の」的解释性用法" aria-label="Permalink to &quot;「の」的解释性用法&quot;">​</a></h4><p>在句子最后一个分句末尾加上 <code>の</code>，能让句子带有 <mark>解释的性质</mark>。这类句子包含着对某事原因的解释性含义，相当于「其实……」「事情是这样的……」。</p><table tabindex="0"><thead><tr><th>形式</th><th>例句</th></tr></thead><tbody><tr><td>基本</td><td>今は忙しいのだ。 // 其实，现在有点忙。</td></tr><tr><td>缩约</td><td>今は忙しいんだ。 // 同上，更口语化。</td></tr><tr><td>疑问</td><td>忙しいの？ // 你很忙吗？——男女皆可</td></tr></tbody></table><ul><li>虽然 <code>のだ</code> 是标准形式，但通常会被 <code>んだ</code> 替代（因为更易于发音）。</li><li>陈述句中，成年男性几乎总会加上表示肯定的 <code>だ</code>；疑问句中的 <code>の</code> 没有性别含义。</li></ul><p>在表达状态时，当使用 <code>の</code> 来表示这种说明性含义时，需要加上 <code>な</code>, 以便将其与表示“所属关系”的含义区分开来。</p><blockquote><p>ジムのだ。// It is of Jim.</p></blockquote><blockquote><p>ジムなのだ。 // It is Jim (with explanatory tone)</p></blockquote><p><strong>关键区别：</strong></p><ul><li>使用说明性的 <code>の</code>：告诉听者「看，原因就在这里」</li><li>不使用 <code>の</code>：只是单纯传递信息</li></ul><hr><h2 id="副词与句末助词" tabindex="-1">副词与句末助词 <a class="header-anchor" href="#副词与句末助词" aria-label="Permalink to &quot;副词与句末助词&quot;">​</a></h2><h3 id="副词的构成" tabindex="-1">副词的构成 <a class="header-anchor" href="#副词的构成" aria-label="Permalink to &quot;副词的构成&quot;">​</a></h3><table tabindex="0"><thead><tr><th>来源</th><th>规则</th><th>例句</th></tr></thead><tbody><tr><td>い形容词</td><td>用 <code>く</code> 替换 <code>い</code></td><td>早い → 早く // 早早地</td></tr><tr><td>な形容词</td><td>加上助词 <code>に</code></td><td>静か → 静かに // 安静地</td></tr></tbody></table><p><strong>注意：</strong> 并非所有副词都源自形容词。像 <code>全然</code> 和 <code>たくさん</code> 这样的词本身就是副词，无需变形即可直接使用。</p><p><strong>场所副词示例：</strong></p><blockquote><p>図書館の中では、静かにする。 // 在图书馆里要安静。</p></blockquote><h3 id="句末助词" tabindex="-1">句末助词 <a class="header-anchor" href="#句末助词" aria-label="Permalink to &quot;句末助词&quot;">​</a></h3><p>句末助词是指总是出现在句子末尾、用来改变句子「语气」或「感觉」的助词。</p><h4 id="「ね」——寻求认同" tabindex="-1">「ね」——寻求认同 <a class="header-anchor" href="#「ね」——寻求认同" aria-label="Permalink to &quot;「ね」——寻求认同&quot;">​</a></h4><p>在句子末尾加上 <code>ね</code>，表示寻求对方对自己所说内容的认同或赞同，相当于「对吧？」。</p><blockquote><p>そうね。 // 是啊。/ 对吧。</p></blockquote><p>男性可能会说 <code>そうだね</code>。</p><h4 id="「よ」——传达新信息" tabindex="-1">「よ」——传达新信息 <a class="header-anchor" href="#「よ」——传达新信息" aria-label="Permalink to &quot;「よ」——传达新信息&quot;">​</a></h4><p>当 <code>よ</code> 被加在句子末尾时，表示说话者正在向听者传达一些 <mark>新信息</mark>，相当于「你知道吗……」。</p><blockquote><p>ボブ：うん。でも、明⽇⾬が降るよ。// Bob: Yeah. But it will rain tomorrow, you know.</p></blockquote><h4 id="「よね」——传达新信息-寻求认同" tabindex="-1">「よね」——传达新信息 + 寻求认同 <a class="header-anchor" href="#「よね」——传达新信息-寻求认同" aria-label="Permalink to &quot;「よね」——传达新信息 + 寻求认同&quot;">​</a></h4><p>将 <code>よ</code> 和 <code>ね</code> 组合形成 <code>よね</code>，用于向听者传达自己想要表达的新观点，同时寻求对方的认同。</p><blockquote><p>ボブは、⿂が好きなんだよね。// Bob, You know, you like fish.</p></blockquote><hr><h2 id="附录-助词速查表" tabindex="-1">附录：助词速查表 <a class="header-anchor" href="#附录-助词速查表" aria-label="Permalink to &quot;附录：助词速查表&quot;">​</a></h2><table tabindex="0"><thead><tr><th>助词</th><th>读法</th><th>功能</th></tr></thead><tbody><tr><td>は</td><td>wa</td><td>主题标记（「至于……」）</td></tr><tr><td>も</td><td>mo</td><td>包含性主题（「也」）</td></tr><tr><td>が</td><td>ga</td><td>指代标记（回答隐含问题）</td></tr><tr><td>を</td><td>o (wo)</td><td>直接宾语</td></tr><tr><td>に</td><td>ni</td><td>目标 / 方向终点</td></tr><tr><td>へ</td><td>e</td><td>方向（朝向，不一定是终点）</td></tr><tr><td>で</td><td>de</td><td>场景 / 方式 / 手段</td></tr><tr><td>と</td><td>to</td><td>并列（「和」）</td></tr><tr><td>や</td><td>ya</td><td>模糊列举（「等等」）</td></tr><tr><td>とか</td><td>toka</td><td>模糊列举（口语）</td></tr><tr><td>の</td><td>no</td><td>所有格 / 名词化 / 解释</td></tr><tr><td>から</td><td>kara</td><td>从……</td></tr><tr><td>まで</td><td>made</td><td>直到……</td></tr><tr><td>ね</td><td>ne</td><td>寻求认同</td></tr><tr><td>よ</td><td>yo</td><td>传达新信息</td></tr></tbody></table><hr><h2 id="附录-动词变形速查表" tabindex="-1">附录：动词变形速查表 <a class="header-anchor" href="#附录-动词变形速查表" aria-label="Permalink to &quot;附录：动词变形速查表&quot;">​</a></h2><h3 id="ru-动词-以-食べる-为例" tabindex="-1">ru-动词（以 食べる 为例） <a class="header-anchor" href="#ru-动词-以-食べる-为例" aria-label="Permalink to &quot;ru-动词（以 食べる 为例）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>形式</th><th>变形</th><th>结果</th></tr></thead><tbody><tr><td>词典形</td><td>—</td><td>食べる</td></tr><tr><td>否定</td><td>去る + ない</td><td>食べない</td></tr><tr><td>过去</td><td>去る + た</td><td>食べた</td></tr><tr><td>过去否定</td><td>否定 + かった</td><td>食べなかった</td></tr></tbody></table><h3 id="u-动词-以-話す-为例" tabindex="-1">u-动词（以 話す 为例） <a class="header-anchor" href="#u-动词-以-話す-为例" aria-label="Permalink to &quot;u-动词（以 話す 为例）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>形式</th><th>变形</th><th>结果</th></tr></thead><tbody><tr><td>词典形</td><td>—</td><td>話す</td></tr><tr><td>否定</td><td>す→さ + ない</td><td>話さない</td></tr><tr><td>过去</td><td>す→し + た</td><td>話した</td></tr><tr><td>过去否定</td><td>否定 + かった</td><td>話さなかった</td></tr></tbody></table><h3 id="形容词变形" tabindex="-1">形容词变形 <a class="header-anchor" href="#形容词变形" aria-label="Permalink to &quot;形容词变形&quot;">​</a></h3><table tabindex="0"><thead><tr><th>形式</th><th>ナ形容词（親切）</th><th>イ形容词（高い）</th></tr></thead><tbody><tr><td>肯定非过去</td><td>親切だ</td><td>高い</td></tr><tr><td>否定非过去</td><td>親切じゃない</td><td>高くない</td></tr><tr><td>肯定过去</td><td>親切だった</td><td>高かった</td></tr><tr><td>否定过去</td><td>親切じゃなかった</td><td>高くなかった</td></tr></tbody></table>',231)])])}const p=e(r,[["render",l]]);export{u as __pageData,p as default};
